class Solution {
public:
    int hardestWorker(int n, vector<vector<int>>& logs) {
        int max_duration = 0;
        int result_id = -1;
        for (int i = 0; i < logs.size(); ++i) {
            int id = logs[i][0];
            int leave = logs[i][1];
            int start = (i == 0) ? 0 : logs[i-1][1];
            int dur = leave - start;
            if (dur > max_duration) {
                max_duration = dur;
                result_id = id;
            } else if (dur == max_duration) {
                if (id < result_id) {
                    result_id = id;
                }
            }
        }
        return result_id;
    }
};

